INSERT INTO nightclub_quests (club_id, npc_id, title, description, quest_type, energy_cost, rewards, dialogue, chain_id, chain_position) VALUES
('bad67b52-9f49-4b98-ae4c-a76007370d19', 'womb_dj_ken', 'Precision Set', 'Ken Ishii challenges you to match Tokyo''s meticulous DJ standard.', 'one_time', 20, '{"cash": 400, "fame": 90, "xp": 35}', '[{"id":"d1","speaker":"Ken Ishii","text":"In Tokyo, every transition must be perfect. One mistake and the crowd knows. Are you precise?","choices":[{"id":"c1a","text":"I practice every mix until it''s flawless.","next_node_id":"d2","effects":{"respect":5}},{"id":"c1b","text":"I blend precision with feeling — both matter.","next_node_id":"d2","effects":{"affinity":4}}]},{"id":"d2","speaker":"Ken Ishii","text":"Good. The sound system here reveals everything. Play Room 1 — prove yourself.","choices":[{"id":"c2","text":"Hai. I''m ready.","next_node_id":null}]}]', NULL, NULL);
